#!/usr/bin/env python3
import base64, os, subprocess

b64_events = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/events.js"), exist_ok=True)
open("/var/www/konverta/src/routes/events.js", "wb").write(base64.b64decode(b64_events))
print("✓ /var/www/konverta/src/routes/events.js")

b64_admin_html = ""
os.makedirs(os.path.dirname("/var/www/konverta/public/admin.html"), exist_ok=True)
open("/var/www/konverta/public/admin.html", "wb").write(base64.b64decode(b64_admin_html))
print("✓ /var/www/konverta/public/admin.html")

print("\n✅ Monitoramento corrigido!")
subprocess.run(["pm2", "restart", "konverta"])